// Check Session Result: Determine if there's a pending session
// Reference: Architecture Design - Check Session Result node
// Fixed: Use correct node names and use original_text for user_input

try {
  // Get session data from current input (step3_CheckSession output)
  const sessionData = $input.first()?.json || null;

  // Get cleaned text data from step2_CleanText (use correct node name)
  const cleanTextItems = $items('step2_CleanText');
  const cleanTextData = (cleanTextItems && Array.isArray(cleanTextItems) && cleanTextItems.length > 0) 
    ? cleanTextItems[0].json 
    : null;

  // Validate required data
  if (!cleanTextData) {
    console.error('Step4_CheckSessionResult: Cannot get data from step2_CleanText');
    // Fallback: Try to get from session data if available
    if (sessionData && sessionData.chat_id) {
      return [{
        json: {
          has_pending: sessionData.pending_slot !== null && 
                      sessionData.pending_slot !== undefined && 
                      sessionData.pending_slot !== 'null',
          session_data: sessionData,
          user_input: '',
          chat_id: sessionData.chat_id,
          user_name: sessionData.user_name || 'User',
          original_text: '',
          message_id: null
        }
      }];
    }
    return [];
  }

  // Check if session has pending (also check for string "null")
  const hasPending = sessionData && 
    sessionData.pending_slot !== null && 
    sessionData.pending_slot !== undefined &&
    sessionData.pending_slot !== 'null';

  // Use original_text for user_input (not clean_query)
  return [{
    json: {
      has_pending: hasPending,
      session_data: sessionData || {},
      user_input: cleanTextData.original_text || '',  // ✅ 使用 original_text
      chat_id: cleanTextData.chat_id,
      user_name: cleanTextData.user_name || 'User',
      original_text: cleanTextData.original_text || '',  // ✅ 保持 original_text
      message_id: cleanTextData.message_id
    }
  }];
} catch (error) {
  console.error('Step4_CheckSessionResult Error:', error);
  return [];
}

// Merge Pending Context: Merge session context with current user input
// Reference: Architecture Design - Merge Pending Context node

const sessionData = $json.session_data || {};
const contextJson = sessionData.context_json || {};
const currentInput = $json.user_input || '';
const originalQuestion = contextJson.original_question || '';

// Merge input: original_question + current_reply
const mergedInput = originalQuestion && currentInput 
  ? `${originalQuestion} ${currentInput}`.trim()
  : currentInput || originalQuestion;

// Merge context
const mergedContext = {
  original_question: originalQuestion || currentInput,
  current_reply: currentInput,
  pending_slot: sessionData.pending_slot,
  collected_context: contextJson
};

return [{
  json: {
    merged_input: mergedInput,  // ✅ "查询执行情况 最近7天"
    merged_context: JSON.stringify(mergedContext),
    session_data: sessionData,
    chat_id: $json.chat_id,
    user_name: $json.user_name,
    original_text: $json.original_text,
    message_id: $json.message_id
  }
}];

// Build Classifier Prompt Input: Construct LLM input for classification
// Reference: Architecture Design - Build Classifier Prompt Input node
// Modified: Fix null value handling in sessionContext
// ✅ v6.2 修复：添加 current_date 变量注入

const allItems = $input.all() || [];
let promptData = {};
let inputData = {};

for (const item of allItems) {
  const json = item.json || {};
  if (json.system_prompt || json.user_prompt_template || json.slug === 'telegram_classifier') {
    promptData = json;
  }
  if (json.merged_input || json.user_input || json.clean_query || json.chat_id) {
    inputData = json;
  }
}

const userInput = inputData.merged_input || inputData.user_input || inputData.clean_query || '';
const sessionData = inputData.session_data || {};

// Fix: Properly handle null values (not string "null")
const pendingSlot = sessionData.pending_slot;
const hasPending = pendingSlot !== null && pendingSlot !== undefined && pendingSlot !== 'null' && pendingSlot !== '';

const sessionContext = hasPending ? {
  has_pending: true,
  pending_slot: pendingSlot,
  pending_question: sessionData.pending_question || null,
  context_json: sessionData.context_json || {}
} : {
  has_pending: false,
  pending_slot: null,
  pending_question: null,
  context_json: sessionData.context_json || {}
};

// ✅ v6.2 修复：获取当前日期（UTC时间，ISO8601格式）
const currentDate = new Date().toISOString().split('T')[0]; // 格式：2026-01-08
const currentDateTime = new Date().toISOString(); // 格式：2026-01-08T12:34:56.789Z

const systemPrompt = promptData.system_prompt || '';
const userPromptTemplate = promptData.user_prompt_template || '';

let userPrompt = userPromptTemplate || `User input: ${userInput}\n\nSession context: ${JSON.stringify(sessionContext)}`;

if (userPromptTemplate) {
  userPrompt = userPrompt
    .replace(/{user_input}/g, userInput)
    .replace(/{session_context}/g, JSON.stringify(sessionContext, null, 2))
    // ✅ v6.2 修复：注入 current_date 变量
    .replace(/{current_date}/g, currentDate)  // 替换 {current_date} 为当前日期（YYYY-MM-DD）
    .replace(/{current_datetime}/g, currentDateTime);  // 可选：如果需要完整时间戳
}

// ✅ v6.2 修复：同时替换 systemPrompt 中的 {current_date}
let finalSystemPrompt = systemPrompt
  .replace(/{current_date}/g, currentDate)
  .replace(/{current_datetime}/g, currentDateTime);

return [{
  json: {
    system_prompt: finalSystemPrompt,
    user_prompt: userPrompt,
    chat_id: inputData.chat_id,
    user_name: inputData.user_name,
    session_data: sessionData,
    original_input: userInput
  }
}];

// Prepare Session Data: Prepare data for Save Session node
// Reference: Architecture Design - Save Session node

const classifyOutput = $json;
const inputData = $items('step9_BuildClassifierPromptInput')?.[0]?.json || {};

const contextJson = {
  original_question: inputData.original_input || '',
  type: classifyOutput.type || 'ambiguous',
  filters: classifyOutput.filters || {},
  time_range: classifyOutput.time_range || {}
};

return [{
  json: {
    chat_id: inputData.chat_id,
    user_name: inputData.user_name,
    pending_slot: classifyOutput.pending_slot || null,
    clarify_question: classifyOutput.clarify_question || null,
    context_json: contextJson,
    expires_at: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString()
  }
}];

// Parse Time Range: Extract time range from Classify Question output
// ✅ v6 优化：同时准备 RPC 函数参数
// Reference: Architecture Design - Parse Time Range node
// Added: Time range validation and RPC parameter preparation

const classifyOutput = $json;
const inputData = $items('step9_BuildClassifierPromptInput')?.[0]?.json || {};

const timeRange = classifyOutput.time_range || {};
const now = new Date();

// Default: last 7 days if not provided
const defaultEndTime = new Date(now);
const defaultStartTime = new Date(now);
defaultStartTime.setDate(now.getDate() - 7);
defaultStartTime.setHours(0, 0, 0, 0);
defaultEndTime.setHours(23, 59, 59, 999);

let startTime = timeRange.start ? new Date(timeRange.start) : defaultStartTime;
let endTime = timeRange.end ? new Date(timeRange.end) : defaultEndTime;
let isDefault = timeRange.is_default !== undefined ? timeRange.is_default : true;

// Data availability range (based on actual database records)
// Earliest: 2025-11-13, Latest: 2025-12-18
const dataEarliest = new Date('2025-11-13T00:00:00.000Z');
const dataLatest = new Date('2025-12-18T23:59:59.999Z');

// Validate and adjust time range to ensure data availability
let warningMessage = null;
let adjusted = false;

// ... (时间范围验证逻辑保持不变) ...
// ===== 准备 RPC 函数参数 (优化版) =====
const filters = classifyOutput.filters || {};

// 始终保持结构完整，避免 HTTP 节点引用出错
const rpcBody = {
  p_start_time: startTime.toISOString(),
  p_end_time: endTime.toISOString(),
  // 统一取值逻辑：优先取 vault_keyword，没有则给 null
  p_vault_name: filters.vault_keyword || filters.vault || null 
};

return [{
  json: {
    start_time: startTime.toISOString(),
    end_time: endTime.toISOString(),
    is_default: isDefault,
    warning_message: warningMessage || (isDefault ? '使用默认时间范围（最近7天）' : null),
    clean_query: inputData.original_input || classifyOutput.original_input || '',
    chat_id: inputData.chat_id || classifyOutput.chat_id,
    user_name: inputData.user_name || classifyOutput.user_name,
    question_type: classifyOutput.type || 'metrics',
    filters: filters,
    time_range_adjusted: adjusted,
    // ✅ 这里的 rpc_body 现在包含了确定存在的 p_vault_name
    rpc_body: rpcBody  
  }
}];

// Prepare RAG Query - Metrics Branch: Prepare RAG query for Metrics questions
// ✅ v7.0 优化：拆分 Metrics 和 Investigate 分支，逻辑更清晰
// ✅ v7.1 修复：正确处理占位符 {enhancedQuery} 和 {clean_query}，传递 system_prompt
// ✅ v7.3 修复：从 MergeData 获取 promptData，从 step17 获取 rpcResponse
// Reference: Architecture Design - Prepare RAG Query node (Metrics branch)

const allItems = $input.all() || [];

// ===== 从多个输入项中提取数据（Metrics 分支） =====
let promptData = null;
let rpcResponse = null;
let timeRangeData = null;

// ✅ v7.3 修复：MergeData 输出包含 step23a 的数据（Prompt + TimeRange）
// 遍历所有输入项，识别不同类型的数据
for (const item of allItems) {
  const json = item.json || {};

  // 识别 step23_GetRAGRetrievePrompt 的输出（有 slug 或 user_prompt_template）
  // ✅ v7.3 修复：MergeData 输出包含这些字段
  if (json.slug || json.user_prompt_template || (json.system_prompt && !json.body && !json.start_time)) {
    promptData = json;
  }

  // 识别时间范围数据（有 start_time 和 end_time）
  // ✅ v7.3 修复：MergeData 输出包含 timeRangeData
  if (json.start_time && json.end_time) {
    timeRangeData = json;
  }
}

// ✅ v7.3 修复：从 step17_QueryMetricsSummary 获取 SQL 统计结果（通过 $items）
// RPC 响应不包含在 MergeData 输出中，需要从 step17 获取
try {
  const step17Data = $items('step17_QueryMetricsSummary')?.[0]?.json || {};
  if (step17Data.body || step17Data.execution_summary || step17Data.statusCode) {
    rpcResponse = step17Data.body || step17Data;
  }
} catch (e) {
  // 如果无法获取 step17 的数据，继续处理（rpcResponse 保持为 null）
  console.log('step30: Cannot get data from step17_QueryMetricsSummary, continuing...');
}

// ===== Metrics分支：处理RPC函数返回格式 =====
const questionType = 'metrics';

// 使用 timeRangeData（从 step16）
const timeRangeFromStep16 = timeRangeData || {};

const sqlStatistics = {
  execution_summary: rpcResponse?.execution_summary || {},
  rebalance_summary: rpcResponse?.rebalance_summary || {},
  market_summary: rpcResponse?.market_summary || {},
  allocation_summary: rpcResponse?.allocation_summary || {},
  time_range: {
    start_time: timeRangeFromStep16.start_time,
    end_time: timeRangeFromStep16.end_time,
    is_default: timeRangeFromStep16.is_default || false
  },
  clean_query: timeRangeFromStep16.clean_query || '',
  chat_id: timeRangeFromStep16.chat_id,
  user_name: timeRangeFromStep16.user_name
};

const cleanQuery = sqlStatistics.clean_query || '';
const timeRange = sqlStatistics.time_range || {};
const chatId = sqlStatistics.chat_id;
const userName = sqlStatistics.user_name;
const filters = timeRangeFromStep16.filters || {};

// ===== 构建增强查询文本（Metrics 分支：使用关键词映射） =====
// 基础关键词映射
const baseKeywords = {
  'metrics': {
    'default': 'autonomous agent routine management task vault protocol APY total capital allocated'
  }
};

// 从用户查询中提取意图关键词
const extractIntent = (userQuery, questionType) => {
  const query = userQuery.toLowerCase();

  // 性能相关（未来扩展）
  if (/性能|performance|速度|speed|延迟|latency/i.test(query)) {
    return 'performance';
  }

  // 资本相关（未来扩展）
  if (/资本|capital|资金|funds|分配|allocation/i.test(query)) {
    return 'capital';
  }

  // 默认
  return 'default';
};

let enhancedQuery = cleanQuery;

// 添加时间范围上下文
if (timeRange.start_time && timeRange.end_time) {
  const startDate = new Date(timeRange.start_time).toISOString().split('T')[0];
  const endDate = new Date(timeRange.end_time).toISOString().split('T')[0];
  enhancedQuery += ` (time range: ${startDate} to ${endDate})`;
} else if (timeRange.start && timeRange.end) {
  const startDate = new Date(timeRange.start).toISOString().split('T')[0];
  const endDate = new Date(timeRange.end).toISOString().split('T')[0];
  enhancedQuery += ` (time range: ${startDate} to ${endDate})`;
}

// 使用执行日志实际短语（而不是抽象关键词）
const intent = extractIntent(cleanQuery, questionType);
const keywords = baseKeywords[questionType]?.[intent] || baseKeywords[questionType]?.['default'] || '';

if (keywords) {
  enhancedQuery += ` ${keywords}`;
}

// ===== 获取并构建 RAG Prompt =====
let ragPrompt = '';
let ragSystemPrompt = '';

// ✅ v7.1 修复：只从 prompt_library 获取，不提供默认值
if (promptData) {
  // ✅ 获取 system_prompt（没有占位符，直接传递）
  ragSystemPrompt = promptData.system_prompt || '';

  // ✅ 获取 user_prompt_template，替换所有占位符
  const userPromptTemplate = promptData.user_prompt_template || '';
  if (userPromptTemplate) {
    ragPrompt = userPromptTemplate
      .replace(/{enhancedQuery}/g, enhancedQuery)  // 替换 {enhancedQuery}
      .replace(/{clean_query}/g, enhancedQuery);   // ✅ 修复：也替换 {clean_query}（使用 enhancedQuery 的值）
    // ✅ 注意：{context} 占位符保留，由 RAG Retrieve 节点自动注入
  }
}

// ===== 构建输出 =====
const output = {
  clean_query: cleanQuery,
  enhanced_query: enhancedQuery,
  chat_id: chatId,
  user_name: userName,
  question_type: questionType,
  time_range: timeRange,
  rag_prompt: ragPrompt,
  rag_system_prompt: ragSystemPrompt,  // ✅ v7.1 新增：传递 system_prompt
  sql_statistics: sqlStatistics,
  filters: filters
};

// ✅ 准备 Metadata Filter 用于 Vector Store Supabase
const metadataFilter = {};

// 提取时间范围（支持多种字段名格式）
const startTime = timeRange.start_time || timeRange.start;
const endTime = timeRange.end_time || timeRange.end;

if (startTime) {
  metadataFilter.start_time = startTime;
}
if (endTime) {
  metadataFilter.end_time = endTime;
}

// 提取金库名称（如果有）
if (filters && filters.vault) {
  metadataFilter.vault_name = filters.vault;
}

// ✅ 添加查询文本，用于内容过滤
if (enhancedQuery) {
  metadataFilter.query_text = enhancedQuery;
}

// ✅ 关键：将 metadataFilter 添加到输出中
output.metadata_filter = metadataFilter;

return [{
  json: output
}];

// Prepare RAG Query - Investigate Branch: Prepare RAG query for Investigate questions
// ✅ v7.0 优化：拆分 Metrics 和 Investigate 分支，逻辑更清晰
// ✅ v7.1 修复：正确处理占位符 {enhancedQuery} 和 {clean_query}，传递 system_prompt，移除默认 prompt
// Reference: Architecture Design - Prepare RAG Query node (Investigate branch)

const allItems = $input.all() || [];

// ===== 从多个输入项中提取数据（Investigate 分支） =====
let promptData = null;
let translationResult = null;

// 遍历所有输入项，识别不同类型的数据
for (const item of allItems) {
  const json = item.json || {};

  // 识别 RAG Retrieve Prompt（有 slug 或 user_prompt_template）
  if (json.slug || json.user_prompt_template || (json.system_prompt && !json.body && !json.start_time)) {
    promptData = json;
  }

  // 识别 step29_MergeTranslationResult 的输出（Investigate 分支）
  // 优先识别：有 enhanced_query 或 translated_query 的数据
  if (json.enhanced_query || json.translated_query || json.was_translated !== undefined) {
    translationResult = json;
  }
}

// ===== 从 translationResult 获取数据 =====
const inputData = translationResult || allItems[0]?.json || {};

const questionType = inputData.question_type || inputData.type || 'investigate';

// ✅ 修复：正确获取 clean_query（优先使用 original_input）
let cleanQuery = inputData.original_input || inputData.clean_query || '';

// ✅ 如果 cleanQuery 仍然为空，尝试从更上游获取
if (!cleanQuery || cleanQuery.trim() === '') {
  try {
    const step10Data = $items('step10_ClassifyQuestion')?.[0]?.json || {};
    const step9Data = $items('step9_BuildClassifierPromptInput')?.[0]?.json || {};
    cleanQuery = step10Data.original_input || step9Data.original_input || '';
  } catch (e) {
    // 忽略错误（节点可能未执行）
  }
}

// ✅ 修复：正确获取 time_range（字段名可能是 start/end 或 start_time/end_time）
let timeRange = {};
if (inputData.time_range) {
  timeRange = {
    start: inputData.time_range.start || inputData.time_range.start_time || null,
    end: inputData.time_range.end || inputData.time_range.end_time || null,
    start_time: inputData.time_range.start_time || inputData.time_range.start || null,
    end_time: inputData.time_range.end_time || inputData.time_range.end || null,
    is_default: inputData.time_range.is_default || false
  };
}

// ✅ 修复：正确获取 filters
const filters = inputData.filters || {};

// ✅ 修复：正确获取 chat_id 和 user_name
const chatId = inputData.chat_id || null;
const userName = inputData.user_name || null;

// ===== 构建增强查询文本（Investigate 分支：使用 LLM 翻译结果） =====
let enhancedQuery = '';

if (translationResult && translationResult.enhanced_query) {
  // Investigate分支：使用 LLM 翻译结果
  enhancedQuery = translationResult.enhanced_query;
} else {
  // Fallback：使用原始查询
  enhancedQuery = cleanQuery;
}

// ===== 获取并构建 RAG Prompt =====
let ragPrompt = '';
let ragSystemPrompt = '';

// ✅ v7.1 修复：只从 prompt_library 获取，不提供默认值
if (promptData) {
  // ✅ 获取 system_prompt（没有占位符，直接传递）
  ragSystemPrompt = promptData.system_prompt || '';

  // ✅ 获取 user_prompt_template，替换所有占位符
  const userPromptTemplate = promptData.user_prompt_template || '';
  if (userPromptTemplate) {
    ragPrompt = userPromptTemplate
      .replace(/{enhancedQuery}/g, enhancedQuery)  // 替换 {enhancedQuery}
      .replace(/{clean_query}/g, enhancedQuery);   // ✅ 修复：也替换 {clean_query}（使用 enhancedQuery 的值）
    // ✅ 注意：{context} 占位符保留，由 RAG Retrieve 节点自动注入
  }
}

// ===== 构建输出 =====
const output = {
  clean_query: cleanQuery,
  enhanced_query: enhancedQuery,
  chat_id: chatId,
  user_name: userName,
  question_type: questionType,
  time_range: timeRange,
  rag_prompt: ragPrompt,
  rag_system_prompt: ragSystemPrompt,  // ✅ v7.1 新增：传递 system_prompt
  filters: filters
};

// ✅ 准备 Metadata Filter 用于 Vector Store Supabase
const metadataFilter = {};

// 提取时间范围（支持多种字段名格式）
const startTime = timeRange.start_time || timeRange.start;
const endTime = timeRange.end_time || timeRange.end;

if (startTime) {
  metadataFilter.start_time = startTime;
}
if (endTime) {
  metadataFilter.end_time = endTime;
}

// 提取金库名称（如果有）
if (filters && filters.vault) {
  metadataFilter.vault_name = filters.vault;
}

// ✅ 添加查询文本，用于内容过滤
if (enhancedQuery) {
  metadataFilter.query_text = enhancedQuery;
}

// ✅ 关键：将 metadataFilter 添加到输出中
output.metadata_filter = metadataFilter;

return [{
  json: output
}];

// Build Prompt Input: Construct LLM input with user question + SQL results + RAG context
// ✅ v6.2 优化：修复 chat_id 和 user_name 丢失问题，确保正确识别 contextData
// Reference: Architecture Design - Build Prompt Input node

const allItems = $input.all() || [];
let promptData = {};
let contextData = {};

// Process all input items
for (const item of allItems) {
  const json = item.json || {};

  // ✅ 修复：优先识别 promptData（更明确的标识）
  // Identify prompt data (from step27_GetAnswerPrompt)
  if (json.system_prompt || json.user_prompt_template || json.slug === 'telegram_answer') {
    promptData = json;
    continue; // 跳过后续处理，避免误识别
  }

  // ✅ 修复：更准确的 contextData 识别逻辑
  // Identify context data (from step34_MergeContext)
  // 检查多个可能的标识字段，确保能识别到 contextData
  if (json.sql_statistics || json.rag_context || json.rag_count !== undefined || 
      json.clean_query || json.question_type) {
    // ✅ 修复：合并 contextData，保留所有字段（包括 chat_id 和 user_name）
    contextData = {
      ...contextData,  // 保留之前已识别的字段
      ...json          // 合并当前项的字段
    };
  }
}

const systemPrompt = promptData.system_prompt || '';
const userPromptTemplate = promptData.user_prompt_template || '';

// Extract data from contextData
const sqlStatistics = contextData.sql_statistics || {};
const ragContext = contextData.rag_context || [];
const cleanQuery = contextData.clean_query || '';
const timeRange = contextData.time_range || {};
const filters = contextData.filters || {};

// ✅ 修复：确保 chat_id 和 user_name 正确提取
// 优先从 contextData 获取，如果没有则尝试从 promptData 获取（备用）
const chatId = contextData.chat_id || promptData.chat_id || null;
const userName = contextData.user_name || promptData.user_name || null;

// ✅ v6.2 优化：格式化时间范围显示
let timeRangeDisplay = '';
if (timeRange.start_time && timeRange.end_time) {
  const startDate = new Date(timeRange.start_time).toISOString().split('T')[0];
  const endDate = new Date(timeRange.end_time).toISOString().split('T')[0];
  timeRangeDisplay = `${startDate} to ${endDate}`;
} else if (timeRange.start && timeRange.end) {
  const startDate = new Date(timeRange.start).toISOString().split('T')[0];
  const endDate = new Date(timeRange.end).toISOString().split('T')[0];
  timeRangeDisplay = `${startDate} to ${endDate}`;
}

// Build user prompt
let userPrompt = userPromptTemplate || `User question: ${cleanQuery}\n\nSQL Statistics:\n${JSON.stringify(sqlStatistics, null, 2)}\n\nRAG Context:\n${JSON.stringify(ragContext, null, 2)}`;

if (userPromptTemplate) {
