    time_range: `${inputData.time_range?.start || ''} 至 ${inputData.time_range?.end || ''}`,
    sql_statistics: JSON.stringify(sqlStatistics, null, 2),
    rag_context: JSON.stringify(ragContext, null, 2),

    // 保留原始字段备用
    chat_id: inputData.chat_id,
    user_name: inputData.user_name
  }
}];

// Build Translation Input: Construct LLM input for query translation
// ✅ v6.3 新增：方案 C 阶段 2 - 构建 LLM 翻译输入
// Reference: Architecture Design - Query Translation node

const allItems = $input.all() || [];
let promptData = {};
let queryData = {};

// Process all input items
for (const item of allItems) {
  const json = item.json || {};

  // Identify prompt data (from step24_GetTranslationPrompt)
  if (json.slug === 'rag_query_translation' || (json.system_prompt && json.slug)) {
    promptData = json;
    continue;
  }

  // Identify query data (from step27_CheckComplexQuery)
  // step27_CheckComplexQuery 传递原始数据并添加 needs_llm_translation 字段
  if (json.original_input || json.clean_query || json.type || json.question_type || json.needs_llm_translation !== undefined) {
    queryData = {
      ...queryData,
      ...json
    };
  }
}

const systemPrompt = promptData.system_prompt || '';
const userPromptTemplate = promptData.user_prompt_template || '';

// Extract query data
const userQuery = queryData.original_input || queryData.clean_query || '';
const questionType = queryData.question_type || queryData.type || 'metrics';
const timeRange = queryData.time_range || {
  start_time: queryData.start_time || null,
  end_time: queryData.end_time || null,
  is_default: queryData.is_default || false
};

// Build user prompt
let userPrompt = userPromptTemplate || `User query: ${userQuery}\n\nQuestion type: ${questionType}\n\nTime range: ${JSON.stringify(timeRange, null, 2)}`;

if (userPromptTemplate) {
  userPrompt = userPrompt
    .replace(/{user_query}/g, userQuery)
    .replace(/{question_type}/g, questionType)
    .replace(/{time_range}/g, JSON.stringify(timeRange, null, 2));
}

return [{
  json: {
    system_prompt: systemPrompt,
    user_prompt: userPrompt,
    original_query: userQuery,
    question_type: questionType,
    time_range: timeRange,
    chat_id: queryData.chat_id || null,
    user_name: queryData.user_name || null
  }
}];

// Merge Translation Result: Merge LLM translation result with original query data
// ✅ v6.3 简化：统一使用 LLM 翻译，修复数据传递问题
// LLM Agent 节点输出格式：{ output: "{\"translated_query\": \"...\", ...}" }（JSON 字符串）

const allItems = $input.all() || [];
let translationResult = null;

// ✅ 修复：尝试从 step25_BuildTranslationInput 获取原始数据（通过 $items 访问）
let originalData = {};
try {
  const buildTranslationInputData = $items('step25_BuildTranslationInput')?.[0]?.json || {};
  if (buildTranslationInputData.original_input || buildTranslationInputData.chat_id) {
    originalData = buildTranslationInputData;
  }
} catch (e) {
  // 如果无法访问，继续处理
}

// Process all input items (from step26_TranslateQuery)
for (const item of allItems) {
  const json = item.json || {};

  // ✅ 修复：识别 LLM translation result (from step26_TranslateQuery)
  // LLM Agent 节点返回格式：{ output: "{\"translated_query\": \"...\", \"confidence\": 0.95, ...}" }
  if (json.output) {
    try {
      // 尝试解析 output 字段（可能是 JSON 字符串或已经是对象）
      const parsedOutput = typeof json.output === 'string' ? JSON.parse(json.output) : json.output;

      // 检查是否包含翻译结果字段
      if (parsedOutput.translated_query || parsedOutput.confidence !== undefined) {
        translationResult = parsedOutput;
        continue;
      }
    } catch (e) {
      // 如果解析失败，检查是否是直接的对象格式
      if (json.translated_query || json.confidence !== undefined) {
        translationResult = json;
        continue;
      }
    }
  }

  // ✅ 修复：检查是否是已解析的翻译结果（直接有 translated_query 字段）
  if (json.translated_query || json.confidence !== undefined) {
    translationResult = json;
    continue;
  }

  // ✅ 修复：如果输入项包含原始数据字段，也合并进来（备用）
  if (json.original_input || json.chat_id || json.user_name || json.time_range) {
    originalData = {
      ...originalData,
      ...json
    };
  }
}

// ✅ 统一使用 LLM 翻译结果
// 如果 LLM 翻译存在，使用它；如果不存在（不应该发生），使用原始查询作为 fallback
const enhancedQuery = translationResult?.translated_query || originalData.original_input || originalData.clean_query || '';

// ✅ 修复：确保所有原始数据字段正确传递
const chatId = originalData.chat_id || null;
const userName = originalData.user_name || null;
const timeRange = originalData.time_range || {
  start_time: originalData.start_time || null,
  end_time: originalData.end_time || null,
  start: originalData.start || null,
  end: originalData.end || null,
  is_default: originalData.is_default || false
};
const filters = originalData.filters || {};
const questionType = originalData.question_type || originalData.type || 'investigate';
const cleanQuery = originalData.original_input || originalData.clean_query || '';

return [{
  json: {
    // ✅ 修复：保留所有必要的原始数据字段
    original_input: cleanQuery,
    clean_query: cleanQuery,
    chat_id: chatId,
    user_name: userName,
    question_type: questionType,
    type: questionType,
    time_range: timeRange,
    filters: filters,

    // ✅ 翻译结果字段
    enhanced_query: enhancedQuery,
    translated_query: translationResult?.translated_query || null,
    translation_confidence: translationResult?.confidence || null,
    translation_keywords: translationResult?.keywords_extracted || null,
    was_translated: translationResult !== null
  }
}];

// Add Question Type: Add question_type to RAG Retrieve output for routing
// ✅ v7.2 修复：安全地获取 question_type，避免访问未执行的节点

const ragOutput = $json || {};

// ✅ 安全地获取 question_type（从上游节点）
let questionType = 'metrics'; // 默认值

// 尝试从 step30 获取（Metrics 分支）
try {
  const step30Data = $items('step30_PrepareRAGQuery_Metrics');
  if (step30Data && step30Data.length > 0 && step30Data[0]?.json?.question_type) {
    questionType = step30Data[0].json.question_type;
  }
} catch (e) {
  // step30 未执行，继续尝试 step31
}

// 如果 step30 没有，尝试从 step31 获取（Investigate 分支）
if (questionType === 'metrics') {
  try {
    const step31Data = $items('step31_PrepareRAGQuery_Investigate');
    if (step31Data && step31Data.length > 0 && step31Data[0]?.json?.question_type) {
      questionType = step31Data[0].json.question_type;
    }
  } catch (e) {
    // step31 也未执行，使用默认值
  }
}

// 合并 RAG 输出和 question_type
return [{
  json: {
    ...ragOutput,
    question_type: questionType
  }
}];

// Step 41_FormatExecutionDetails
const rpcResponse = $json.body || $json;
const inputData = $items('step38_ParseLookupFilters')?.[0]?.json || {}; // 建议对齐到 step38

const mode = rpcResponse.mode || 'detail';
const execution = rpcResponse.execution || rpcResponse.latest_execution || null;
const totalCount = rpcResponse.total_count || (execution ? 1 : 0);

return [{
  json: {
    ...rpcResponse, // 保留 mode, total_count, failed_count 等
    execution: execution,
    execution_id: execution?.id || null,
    clean_query: inputData.original_input || '',
    chat_id: inputData.chat_id,
    user_name: inputData.user_name,
    question_type: 'lookup',
    filters: inputData.filters || {},
    time_range: inputData.time_range || {}
  }
}];

// Check Data Sufficiency: Determine if SQL results are sufficient to answer the question
// ✅ v7.3 修复：优化数据获取逻辑，修复 fast_track 判断
// Reference: Architecture Design - Fast Track Gate

const inputData = $json || {};
const sqlBody = inputData.body || inputData || {};

// ✅ 修复：从上游节点获取 clean_query
let cleanQuery = inputData.clean_query || '';
if (!cleanQuery) {
  try {
    const step16Data = $items('step16_ParseTimeRange')?.[0]?.json || {};
    cleanQuery = step16Data.clean_query || '';
  } catch (e) {
    // 如果无法获取，使用空字符串
  }
}

const query = cleanQuery.toLowerCase();

// ✅ 判断 SQL 统计是否有数据
const hasStats = sqlBody.execution_summary && 
                 sqlBody.execution_summary.total_executions > 0;

// ✅ 判断用户是否询问"为什么"、"原因"、"详情"等需要深度分析的问题
const needsWhy = /\b(why|reason|detail|explain|peak|insight|原因|为什么|详情|解释)\b/.test(query);

// ✅ 判断是否为简单统计查询（最高/最低/平均等）
const isSimpleStats = /\b(highest|lowest|average|max|min|最多|最少|最高|最低|平均)\b/.test(query);

// ✅ fast_track 逻辑：
// - 有统计数据 AND
// - 不需要"为什么"分析 AND
// - (是简单统计查询 OR 查询不涉及具体执行详情)
const fastTrack = hasStats && !needsWhy && (isSimpleStats || !needsWhy);

return [{
  json: {
    ...inputData,
    fast_track: fastTrack,
    has_stats: hasStats,
    needs_why: needsWhy,
    is_simple_stats: isSimpleStats
  }
}];

// Merge RAG Prompt Data: Merge RAG Prompt with time range data for RAG query preparation
// ✅ v7.3 新增：合并 RAG Prompt 和时间范围数据，用于准备 RAG 查询
// Reference: Architecture Design - RAG Query Preparation

const allItems = $input.all() || [];
let promptData = null;
let timeRangeData = null;

// 遍历所有输入项，识别不同类型的数据
for (const item of allItems) {
  const json = item.json || {};

  // 识别 step23_GetRAGRetrievePrompt 的输出（有 slug 或 user_prompt_template）
  if (json.slug || json.user_prompt_template || (json.system_prompt && !json.body && !json.start_time)) {
    promptData = json;
  }

  // 识别时间范围数据（有 start_time 和 end_time）
  if (json.start_time && json.end_time) {
    timeRangeData = json;
  }
}

// ✅ 如果时间范围数据不在输入中，从 step16 获取
if (!timeRangeData) {
  try {
    const step16Data = $items('step16_ParseTimeRange')?.[0]?.json || {};
    if (step16Data.start_time && step16Data.end_time) {
      timeRangeData = step16Data;
    }
  } catch (e) {
    // 如果无法获取，继续处理
  }
}

// 合并数据并输出
return [{
  json: {
    ...promptData,
    ...timeRangeData,
    clean_query: timeRangeData?.clean_query || promptData?.clean_query || '',
    chat_id: timeRangeData?.chat_id || promptData?.chat_id || null,
    user_name: timeRangeData?.user_name || promptData?.user_name || null,
    filters: timeRangeData?.filters || {}
  }
}];
